import{_ as e,o as a,c as i,b as h}from"./app.ea8c1143.js";const d={},r=h('<h2 id="\u6570\u636E" tabindex="-1"><a class="header-anchor" href="#\u6570\u636E" aria-hidden="true">#</a> \u6570\u636E</h2><p>\u5468\u671F: 2022-12-26 \u5230 2023-01-29 (\u5171 35 \u5929)</p><p>\u672C\u6708\u8BB0\u5F55\u6570\u636E\u5982\u4E0B:</p><ul><li>\u603B\u65F6\u957F 157 \u5C0F\u65F6 19 \u5206\u949F</li><li>\u6709\u8BB0\u5F55\u5929\u6570 32 \u5929</li><li>\u5E73\u5747\u6BCF\u5929\u8BB0\u5F55\u65F6\u957F 3 \u5C0F\u65F6 30 \u5206\u949F</li></ul><img src="https://pocket.haydenhayden.com/blog/202302031421364.png" width="300"><h2 id="o1-\u5B66\u4E60" tabindex="-1"><a class="header-anchor" href="#o1-\u5B66\u4E60" aria-hidden="true">#</a> O1 \u5B66\u4E60</h2><h3 id="_1-1-\u770B\u4E66" tabindex="-1"><a class="header-anchor" href="#_1-1-\u770B\u4E66" aria-hidden="true">#</a> 1.1 \u770B\u4E66</h3><img src="https://pocket.haydenhayden.com/blog/202302031429509.PNG" width="300"><p>1 \u6708\u9605\u8BFB\u65F6\u957F\u5DF2\u8FBE\u6807\u3002</p><p>\u8BFB\u5B8C\u4E86\u300A\u94F6\u6CB3\u4E4B\u5FC3: \u5929\u5782\u65E5\u66AE\u300B, \u5FEB\u901F\u8FC7\u4E86\u4E00\u904D \u300A\u7F8E\u56FD\u53CD\u5BF9\u7F8E\u56FD\u300B,\u53E6\u5916\u770B\u4E86\u4E00\u70B9 \u300A\u7F6E\u8EAB\u4E8B\u5185\u300B\u3002</p><p>\u7B2C\u4E00\u6B21\u770B\u592A\u7A7A\u6B4C\u5267\u79D1\u5E7B, \u611F\u89C9\u5F88\u6709\u610F\u601D, \u50CF\u6211\u4EEC\u8FD9\u6837\u7684\u5B9A\u5C45\u5728\u661F\u7403\u4E0A\u7684\u4EBA\u7C7B\u5728\u672A\u6765\u662F\u539F\u59CB\u4EBA, \u5904\u4E8E\u79D1\u6280\u53D1\u5C55\u7684\u521D\u7EA7\u9636\u6BB5\u3002</p><p>\u800C\u5C45\u4F4F\u5728\u4E16\u4EE3\u98DE\u8239\u7684\u5DE1\u903B\u8005\u62E5\u6709\u66F4\u5F3A\u5927\u7684\u79D1\u6280, \u4ED6\u4EEC\u5DE1\u903B\u94F6\u6CB3, \u4FDD\u536B\u4EBA\u7C7B\u3002</p><p>\u66F4\u6709\u94C1\u4EBA\u8FD9\u79CD\u8EAB\u4F53\u7EC6\u80DE\u4E3A\u7EB3\u7C73\u673A\u5668\u4EBA\u7684\u4EBA\u7C7B, \u8FD8\u6709\u94F6\u6CB3\u4EBA\u5DF2\u7ECF\u4E0D\u77E5\u9053\u80FD\u4E0D\u80FD\u79F0\u4E3A\u4EBA\u7C7B, \u4ED6\u4EEC\u5728\u5F88\u591A\u4EBF\u5E74\u524D\u4E0E\u6211\u4EEC\u6709\u76F8\u540C\u7684 DNA, \u800C\u73B0\u5728\u5DF2\u7ECF\u4E0D\u5177\u6709\u4EBA\u7C7B\u7684\u5F62\u6001\u4E86, \u4ED6\u4EEC\u6781\u4E3A\u5F3A\u5927, \u63A5\u8FD1\u795E\u660E\u3002</p><p>\u8FD8\u6709\u4E00\u79CD\u667A\u8111\u540D\u4E3A\u6C99\u8FBE\u514B, \u53EA\u8981\u6709\u4EBA\u7C7B\u7684\u5730\u65B9\u5C31\u6709\u6C99\u8FBE\u514B, \u6C99\u8FBE\u514B\u6C38\u8FDC\u662F\u4EBA\u7C7B\u53EF\u4FE1\u7684\u4F19\u4F34, \u5DF2\u7ECF\u523B\u5370\u5728\u6240\u6709\u4EBA\u7684 DNA \u91CC\u3002\u4ED6\u4EEC\u6C38\u8FDC\u4E0D\u4F1A\u6492\u8C0E, \u4F46\u4ECE\u4E0D\u505A\u51B3\u5B9A, \u4ED6\u4EEC\u4E3A\u4EBA\u7C7B\u63D0\u4F9B\u51B3\u7B56\u7684\u4F9D\u636E\u3002</p><h3 id="_1-2-\u82F1\u8BED" tabindex="-1"><a class="header-anchor" href="#_1-2-\u82F1\u8BED" aria-hidden="true">#</a> 1.2 \u82F1\u8BED</h3><h4 id="\u80CC\u5355\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u80CC\u5355\u8BCD" aria-hidden="true">#</a> \u80CC\u5355\u8BCD</h4><p>\u5B66\u4E60 120 \u4E2A, \u590D\u4E60 1248 \u6B21\u3002</p><p>\u6253\u5361 31/35 \u5929\u3002</p><h4 id="\u82F1\u8BED\u9605\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u82F1\u8BED\u9605\u8BFB" aria-hidden="true">#</a> \u82F1\u8BED\u9605\u8BFB</h4><p>\u6253\u5361 15/35 \u5929\u3002</p><h2 id="o2-\u5DE5\u4F5C" tabindex="-1"><a class="header-anchor" href="#o2-\u5DE5\u4F5C" aria-hidden="true">#</a> O2 \u5DE5\u4F5C</h2><p>Argo \u7EC4\u4EF6\u5E93\u57FA\u7840\u529F\u80FD\u5DF2\u7ECF\u5B8C\u6210, \u4F46\u662F\u8FD8\u6709\u5F88\u591A\u7EC6\u8282\u9700\u8981\u5B8C\u5584, \u4F8B\u5982\u4EE3\u7801\u89C4\u8303, CI/CD \u7B49\u3002</p><h2 id="review" tabindex="-1"><a class="header-anchor" href="#review" aria-hidden="true">#</a> Review</h2><h3 id="\u4EFB\u52A1\u57FA\u672C\u8FBE\u6807" tabindex="-1"><a class="header-anchor" href="#\u4EFB\u52A1\u57FA\u672C\u8FBE\u6807" aria-hidden="true">#</a> \u4EFB\u52A1\u57FA\u672C\u8FBE\u6807</h3><p>1 \u6708\u5305\u542B\u4E86 10 \u5929\u6625\u8282\u5047\u671F, \u4ECE\u8FD9\u4E2A\u89D2\u5EA6\u770B, \u5404\u9879 habit \u90FD\u8FBE\u6807\u4E86\u3002</p><h3 id="\u5DE5\u4F5C\u9879\u6709\u989D\u5916\u60CA\u559C" tabindex="-1"><a class="header-anchor" href="#\u5DE5\u4F5C\u9879\u6709\u989D\u5916\u60CA\u559C" aria-hidden="true">#</a> \u5DE5\u4F5C\u9879\u6709\u989D\u5916\u60CA\u559C</h3><p>\u5728\u65B0\u9879\u76EE\u5F00\u59CB\u63A8\u52A8\u6BCF\u5929 Code Review, \u5F97\u5230 leader \u53CA\u540C\u4E8B\u7684\u652F\u6301\u3002</p><p>\u63A5\u4E0B\u6765\u9700\u8981\u6C89\u6DC0\u6700\u4F73\u5B9E\u8DF5, \u4F5C\u4E3A Code Review \u7684\u6307\u5BFC\u624B\u518C\u3002</p><h3 id="\u82F1\u8BED\u9605\u8BFB\u9700\u8981\u6539\u8FDB" tabindex="-1"><a class="header-anchor" href="#\u82F1\u8BED\u9605\u8BFB\u9700\u8981\u6539\u8FDB" aria-hidden="true">#</a> \u82F1\u8BED\u9605\u8BFB\u9700\u8981\u6539\u8FDB</h3><p>\u82F1\u8BED\u9605\u8BFB\u7684\u6253\u5361\u7387\u53EA\u6709 42%, \u8FD9\u4E2A\u9700\u8981\u6539\u8FDB\u3002 \u53CD\u601D:</p><ul><li>1 \u6708\u4EFD\u524D\u534A\u6BB5\u5728\u770B\u4E66\u4E0A\u82B1\u8D39\u65F6\u95F4\u6BD4\u8F83\u591A, \u4E0B\u73ED\u65F6\u6CA1\u6709\u7CBE\u529B\u770B\u82F1\u8BED\u6587\u7AE0</li><li>\u63D0\u9AD8\u82F1\u6587\u9605\u8BFB\u7684\u4F18\u5148\u7EA7, \u65F6\u95F4\u5206\u914D\u5230\u653E\u5230\u4E0A\u73ED\u5730\u94C1\u4E0A, \u4E0B\u73ED\u65F6\u518D\u770B\u4E66</li></ul><h3 id="\u4E13\u6CE8\u529B\u9700\u8981\u63D0\u5347" tabindex="-1"><a class="header-anchor" href="#\u4E13\u6CE8\u529B\u9700\u8981\u63D0\u5347" aria-hidden="true">#</a> \u4E13\u6CE8\u529B\u9700\u8981\u63D0\u5347</h3><ul><li><p>\u7B2C\u4E8C\u5468\u5206\u914D\u7684\u4EFB\u52A1\u6CA1\u6709\u660E\u786E deadline, \u5BFC\u81F4\u610F\u8BC6\u4E0A\u6CA1\u6709 sense of urgency, \u6548\u7387\u4F4E \u6539\u8FDB: \u5373\u4FBF\u56E2\u961F\u6CA1\u6709\u660E\u786E deadline, \u4E5F\u8981\u81EA\u5DF1\u7ED9\u81EA\u5DF1\u8BBE\u5B9A deadline, \u4FDD\u8BC1\u81EA\u5DF1\u7684\u6548\u7387</p></li><li><p>logseq \u4E2D\u4F7F\u7528\u756A\u8304\u949F\u8FD8\u6709\u6709\u70B9\u9EBB\u70E6, \u6709\u65F6\u5019\u4F1A\u5FD8\u8BB0\u6253\u5F00\u756A\u8304\u949F, \u5BFC\u81F4\u6CA1\u6709\u8BB0\u5F55, \u6709\u65F6\u5E72\u8106\u5C31\u4E0D\u7528\u756A\u8304\u949F\u4E86 \u6539\u8FDB:</p></li></ul><ol><li>\u7528\u756A\u8304\u949F\u7684\u65F6\u5019, \u4E00\u5B9A\u8981\u6253\u5F00\u756A\u8304\u949F, \u4E0D\u80FD\u5FD8\u8BB0</li><li>\u957F\u7EBF: \u9700\u8981\u5347\u7EA7 Agenda \u63D2\u4EF6, \u8BA9\u756A\u8304\u949F\u7684\u4F7F\u7528\u66F4\u52A0\u65B9\u4FBF</li><li>\u6709\u610F\u8BC6\u4F7F\u7528\u756A\u8304\u949F\u7BA1\u7406\u5DE5\u4F5C\u65F6\u95F4, \u63D0\u9AD8\u4E13\u6CE8\u529B</li></ol>',34),n=[r];function l(t,c){return a(),i("div",null,n)}var o=e(d,[["render",l],["__file","index.html.vue"]]);export{o as default};
